// pallet-mesh-pallet.js — createPalletMesh: 팔레트 종류별 3D 빌더

function createPalletMesh(pallet) {
  const group = new THREE.Group();
  group.userData.palletId = pallet.id;

  const W = pallet.w, D = pallet.d, H = pallet.h;
  const WH = pallet.wallH || 600;
  const t = 40; // wall thickness

  const deckColor   = 0x8a9eab;
  const beamColor   = 0x6a8090;
  const wallColor   = 0x7090a8;
  const postColor   = 0x5a7888;
  const mat      = createMetalMaterial(deckColor);
  const beamMat  = createMetalMaterial(beamColor, 0.4, 0.85);
  const wallMat  = createMetalMaterial(wallColor, 0.45, 0.88);
  const postMat  = createMetalMaterial(postColor, 0.4, 0.9);

  const pid = pallet.id;
  const type = pallet.type || 'flat';

  // ── 공통: 바닥 팔레트 (옥타프레임은 제외) ──
  if (type !== 'octaframe' && type !== 'meshpallet' && type !== 'drum_h' && type !== 'gamma2_mq4') {
    buildBasePallet(group, W, D, H, mat, beamMat, pid);
  }

  // ── 형태별 상부 구조 ──
  if (type === 'box') {
    // 박스형: 4면 판넬 + 상단 프레임
    const wallY = H + WH/2;
    // 앞/뒤 벽
    [-(D/2 - t/2), (D/2 - t/2)].forEach(z => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(W, WH, t), wallMat, pid, wallY);
      m.position.z = z;
      // 가로 슬롯 라인
      for (let r = 1; r < 4; r++) {
        const slot = new THREE.Mesh(new THREE.BoxGeometry(W + 2, 8, t + 2),
          createMetalMaterial(0x4a6070, 0.5, 0.9));
        slot.position.set(0, -WH/2 + (WH/4)*r, 0);
        slot.userData = { type: 'pallet', palletId: pid };
        m.add(slot);
      }
    });
    // 좌/우 벽
    [-(W/2 - t/2), (W/2 - t/2)].forEach(x => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(t, WH, D), wallMat, pid, wallY);
      m.position.x = x;
    });
    // 상단 프레임
    const fT = 30;
    [-(D/2), (D/2)].forEach(z => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(W, fT, fT), beamMat, pid, H + WH - fT/2);
      m.position.z = z;
    });
    [-(W/2), (W/2)].forEach(x => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(fT, fT, D), beamMat, pid, H + WH - fT/2);
      m.position.x = x;
    });

  } else if (type === 'post') {
    // 포스트형: 4코너 기둥 + 상단 연결 빔
    const postW = 60, postD = 60;
    const corners = [[-W/2+postW/2, -D/2+postD/2],[W/2-postW/2, -D/2+postD/2],
                     [-W/2+postW/2,  D/2-postD/2],[W/2-postW/2,  D/2-postD/2]];
    corners.forEach(([cx, cz]) => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(postW, WH, postD), postMat, pid, H + WH/2);
      m.position.x = cx; m.position.z = cz;
      // 기둥 리브
      for (let r = 0; r < 3; r++) {
        const rib = new THREE.Mesh(new THREE.BoxGeometry(postW+10, 10, postD+10),
          createMetalMaterial(0x4a6070));
        rib.position.y = -WH/2 + WH/4*(r+1);
        rib.userData = { type:'pallet', palletId: pid };
        m.add(rib);
      }
    });
    // 상단 연결 빔
    const bT = 40;
    [-(D/2-postD/2), (D/2-postD/2)].forEach(z => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(W, bT, bT), beamMat, pid, H + WH - bT/2);
      m.position.z = z;
    });
    [-(W/2-postW/2), (W/2-postW/2)].forEach(x => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(bT, bT, D), beamMat, pid, H + WH - bT/2);
      m.position.x = x;
    });

  } else if (type === 'sideboard') {
    // 사이드보드형: 앞뒤 2면만 판넬
    const wallY = H + WH/2;
    [-(D/2 - t/2), (D/2 - t/2)].forEach(z => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(W, WH, t), wallMat, pid, wallY);
      m.position.z = z;
      for (let r = 1; r < 4; r++) {
        const slot = new THREE.Mesh(new THREE.BoxGeometry(W+2, 8, t+2),
          createMetalMaterial(0x4a6070, 0.5, 0.9));
        slot.position.set(0, -WH/2 + (WH/4)*r, 0);
        slot.userData = { type: 'pallet', palletId: pid };
        m.add(slot);
      }
    });
    // 코너 보강 포스트
    const corners = [[-W/2+25,-D/2+25],[W/2-25,-D/2+25],[-W/2+25,D/2-25],[W/2-25,D/2-25]];
    corners.forEach(([cx,cz]) => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(50, WH, 50), postMat, pid, H+WH/2);
      m.position.x = cx; m.position.z = cz;
    });
  } else if (type === 'octaframe') {

    const fMat = createMetalMaterial(0xb0bcc4, 0.25, 0.88); // 회색 프레임
    const bMat = createMetalMaterial(0x2a8ec0, 0.20, 0.85); // 파란 브레이스

    const bW  = 50;           // 프레임 바 두께
    const drumR = W * 0.21;   // 드럼 반경 (홈 크기)
    const cY  = drumR * 1.2;  // 프레임 중심 높이 (바닥 다리 포함)
    const legH = drumR * 0.3; // 다리 높이

    // Z 위치: 앞 / 중 / 뒤
    const zF = -D/2 + bW*0.5;
    const zM = 0;
    const zB =  D/2 - bW*0.5;
    const zRows = [zF, zM, zB];

    // ── 1. 나비형 연속 프레임 3열 ──
    zRows.forEach(fz => {
      buildButterflyFrame(group, W, drumR, bW, fMat, pid, cY, fz);
    });

    const xSlots = [-W/4, W/4];
    const zPairs = [[zF, zM], [zM, zB]];

    xSlots.forEach(sx => {
      zPairs.forEach(([z1, z2]) => {
        const segZ = Math.abs(z2 - z1);
        const midZ = (z1 + z2) / 2;
        const braceH = drumR * 1.6;
        const braceW = bW * 0.7;

        // 상단 역삼각 브레이스: 위가 넓고 아래가 좁은 사다리꼴 판
        // → 3개의 직사각 빔으로 표현 (좌대각, 우대각, 하단수직)
        const diagLen = Math.sqrt((segZ*0.5)**2 + braceH**2);
        const angX = Math.atan2(braceH, segZ * 0.5);

        // 좌대각 빔
        const bL = new THREE.Mesh(new THREE.BoxGeometry(braceW, braceW, diagLen), bMat);
        bL.position.set(sx, cY + drumR*0.1, midZ - segZ*0.25);
        bL.rotation.x = angX;
        bL.userData = { type:'pallet', palletId:pid }; bL.castShadow = true;
        group.add(bL);

        // 우대각 빔
        const bR = new THREE.Mesh(new THREE.BoxGeometry(braceW, braceW, diagLen), bMat);
        bR.position.set(sx, cY + drumR*0.1, midZ + segZ*0.25);
        bR.rotation.x = -angX;
        bR.userData = { type:'pallet', palletId:pid }; bR.castShadow = true;
        group.add(bR);

        // 중앙 수직 기둥 (브레이스 교차점)
        const bV = new THREE.Mesh(new THREE.BoxGeometry(braceW, braceH, braceW), bMat);
        bV.position.set(sx, cY - drumR*0.6, midZ);
        bV.userData = { type:'pallet', palletId:pid }; bV.castShadow = true;
        group.add(bV);
      });
    });

    // ── 3. 외곽 좌우 사이드 세로 연결 빔 ──
    const sideX = [-(W/2 + bW*0.6), W/2 + bW*0.6];
    sideX.forEach(sx => {
      // 앞→뒤 상단 레일
      const topR = new THREE.Mesh(new THREE.BoxGeometry(bW, bW, D), fMat);
      topR.position.set(sx, cY + drumR*0.88, 0);
      topR.userData = { type:'pallet', palletId:pid }; topR.castShadow = true;
      group.add(topR);
      // 앞→뒤 하단 레일
      const botR = new THREE.Mesh(new THREE.BoxGeometry(bW, bW, D), fMat);
      botR.position.set(sx, cY - drumR*0.88, 0);
      botR.userData = { type:'pallet', palletId:pid }; botR.castShadow = true;
      group.add(botR);
      // 수직 사이드 판 (앞/뒤 열에만)
      [zF, zB].forEach(fz => {
        const sv = new THREE.Mesh(new THREE.BoxGeometry(bW, drumR*2.0, bW), fMat);
        sv.position.set(sx, cY, fz);
        sv.userData = { type:'pallet', palletId:pid }; sv.castShadow = true;
        group.add(sv);
      });
    });

    // ── 4. 바닥 다리 ──
    // 앞뒤 프레임 아래 짧은 다리 (이미지에서 프레임이 바닥에서 살짝 떠있음)
    [zF, zB].forEach(fz => {
      [-(W/2+bW*0.3), -W/4, W/4, W/2+bW*0.3].forEach(lx => {
        const leg = new THREE.Mesh(new THREE.BoxGeometry(bW*0.8, legH, bW*0.8), fMat);
        leg.position.set(lx, legH/2, fz);
        leg.userData = { type:'pallet', palletId:pid }; leg.castShadow = true;
        group.add(leg);
      });
    });

  } else if (type === 'bulkbox') {
    // 벌크박스형: 이미지2 — 금속 베이스 + 대형 컨테이너 박스 + 덮개
    const boxColor = 0xc8a882;
    const lidColor = 0xbf9f78;
    const seamColor = 0xb09060;
    const boxMat2 = createMetalMaterial(boxColor, 0.7, 0.05);
    const lidMat  = createMetalMaterial(lidColor, 0.65, 0.05);
    const seamMat = createMetalMaterial(seamColor, 0.8, 0.05);
    const wallThick = 30;

    // 컨테이너 4면 벽
    // 앞/뒤
    [-(D/2 - wallThick/2), (D/2 - wallThick/2)].forEach(z => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(W, WH, wallThick), boxMat2, pid, H + WH/2);
      m.position.z = z;
      // 수직 심 라인 (점선 효과)
      for (let s = 1; s < 3; s++) {
        const seam = new THREE.Mesh(new THREE.BoxGeometry(4, WH, wallThick+2), seamMat);
        seam.position.x = -W/2 + W/3*s;
        seam.userData = { type:'pallet', palletId:pid };
        m.add(seam);
      }
    });
    // 좌/우
    [-(W/2 - wallThick/2), (W/2 - wallThick/2)].forEach(x => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(wallThick, WH, D), boxMat2, pid, H + WH/2);
      m.position.x = x;
    });
    // 덮개 (살짝 넘침 + 경사)
    const lidOverhang = 30;
    const lidThick = 40;
    const lid = addPalletMesh(group,
      new THREE.BoxGeometry(W + lidOverhang*2, lidThick, D + lidOverhang*2),
      lidMat, pid, H + WH + lidThick/2);
    // 덮개 앞쪽 접힘 표현
    const foldMat = createMetalMaterial(0xaa8860, 0.7, 0.04);
    const fold = addPalletMesh(group,
      new THREE.BoxGeometry(W + lidOverhang*2, lidThick*0.4, lidOverhang),
      foldMat, pid, H + WH + lidThick*0.2);
    fold.position.z = D/2 + lidOverhang/2;

  } else if (type === 'meshpallet') {

    const pW = W;   // 전체 가로 (1430 기준)
    const pD = D;   // 전체 세로 (1090 기준)
    const pH = WH;  // 벽 높이 (920 기준)
    const pT = 15;  // 파이프 단면 크기 (15×15mm)
    const pT2 = 20; // 상부 파이프 (20×20mm)

    const frameMat3  = createMetalMaterial(0x8a9eab, 0.35, 0.88);
    const meshMat    = createMetalMaterial(0x7a8e9a, 0.5,  0.75);
    const topRailMat = createMetalMaterial(0x9aaebb, 0.3,  0.90);

    // ── 1. 하부 프레임 (파렛트 바닥) ──
    const baseH = H;
    const baseT = 30;

    // 외곽 가로 빔 (앞/뒤)
    [-pD/2 + baseT/2, pD/2 - baseT/2].forEach(bz => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(pW, baseT, baseT), frameMat3, pid, baseT/2);
      m.position.z = bz;
    });
    // 외곽 세로 빔 (좌/우)
    [-pW/2 + baseT/2, pW/2 - baseT/2].forEach(bx => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(baseT, baseT, pD), frameMat3, pid, baseT/2);
      m.position.x = bx;
    });
    // 중간 세로 빔 (433-504-433 분할, 2개)
    const midX1 = -pW/2 + pW * 433/1430;
    const midX2 =  pW/2 - pW * 433/1430;
    [midX1, midX2].forEach(bx => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(baseT, baseT, pD), frameMat3, pid, baseT/2);
      m.position.x = bx;
    });
    // 중간 가로 빔 (305 간격, 2개)
    const midZ1 = -pD/2 + pD * 305/1090;
    const midZ2 =  pD/2 - pD * 305/1090;
    [midZ1, midZ2].forEach(bz => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(pW, baseT * 0.6, baseT * 0.6), frameMat3, pid, baseT * 0.3);
      m.position.z = bz;
    });
    // 하부 지지 발 (4코너 + 중앙 6개 = 8개)
    const legH2 = baseH - baseT;
    const legT  = baseT * 1.2;
    [
      [-pW/2 + legT/2, -pD/2 + legT/2], [pW/2 - legT/2, -pD/2 + legT/2],
      [-pW/2 + legT/2,  pD/2 - legT/2], [pW/2 - legT/2,  pD/2 - legT/2],
      [midX1, -pD/2 + legT/2], [midX2, -pD/2 + legT/2],
      [midX1,  pD/2 - legT/2], [midX2,  pD/2 - legT/2],
    ].forEach(([lx, lz]) => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(legT, legH2, legT), frameMat3, pid, legH2/2);
      m.position.x = lx; m.position.z = lz;
    });

    // ── 2. 면판 (앞/뒤) — Z방향 끝 ──
    const wallT  = pT;
    const wallH2 = pH;

    [-pD/2 - wallT/2, pD/2 + wallT/2].forEach(wz => {
      const wW = pW * (1400/1430);
      // 상단 빔 (20×20)
      const top = new THREE.Mesh(new THREE.BoxGeometry(wW, pT2, pT2), topRailMat);
      top.position.set(0, baseH + wallH2 - pT2/2, wz);
      top.userData = { type:'pallet', palletId:pid }; top.castShadow = true; group.add(top);
      // 하단 빔
      const bot = new THREE.Mesh(new THREE.BoxGeometry(wW, wallT, wallT), frameMat3);
      bot.position.set(0, baseH + wallT/2, wz);
      bot.userData = { type:'pallet', palletId:pid }; bot.castShadow = true; group.add(bot);
      // 좌우 수직 빔
      [-wW/2 + wallT/2, wW/2 - wallT/2].forEach(vx => {
        const v = new THREE.Mesh(new THREE.BoxGeometry(wallT, wallH2, wallT), frameMat3);
        v.position.set(vx, baseH + wallH2/2, wz);
        v.userData = { type:'pallet', palletId:pid }; v.castShadow = true; group.add(v);
      });
      // 내부 수직 메시 빔 (262 간격 4개)
      const vCount = 4;
      const vSpacing = wW / (vCount + 1);
      for (let i = 1; i <= vCount; i++) {
        const vx = -wW/2 + vSpacing * i;
        const vm = new THREE.Mesh(new THREE.BoxGeometry(wallT, wallH2, wallT * 0.7), meshMat);
        vm.position.set(vx, baseH + wallH2/2, wz);
        vm.userData = { type:'pallet', palletId:pid }; vm.castShadow = true; group.add(vm);
      }
      // 내부 수평 메시 빔 (435+435 분할, 2개)
      [baseH + wallH2 * 435/920, baseH + wallH2 * 870/920].forEach(hy => {
        const hm = new THREE.Mesh(new THREE.BoxGeometry(wW, wallT * 0.7, wallT * 0.7), meshMat);
        hm.position.set(0, hy, wz);
        hm.userData = { type:'pallet', palletId:pid }; hm.castShadow = true; group.add(hm);
      });
    });

    // ── 3. 측판 (좌/우) — X방향 끝 ──
    const sW = pD * (1039/1090);
    [-pW/2 - wallT/2, pW/2 + wallT/2].forEach(wx => {
      // 상단 빔
      const top = new THREE.Mesh(new THREE.BoxGeometry(pT2, pT2, sW), topRailMat);
      top.position.set(wx, baseH + wallH2 - pT2/2, 0);
      top.userData = { type:'pallet', palletId:pid }; top.castShadow = true; group.add(top);
      // 하단 빔
      const bot = new THREE.Mesh(new THREE.BoxGeometry(wallT, wallT, sW), frameMat3);
      bot.position.set(wx, baseH + wallT/2, 0);
      bot.userData = { type:'pallet', palletId:pid }; bot.castShadow = true; group.add(bot);
      // 전후 수직 빔
      [-sW/2 + wallT/2, sW/2 - wallT/2].forEach(vz => {
        const v = new THREE.Mesh(new THREE.BoxGeometry(wallT, wallH2, wallT), frameMat3);
        v.position.set(wx, baseH + wallH2/2, vz);
        v.userData = { type:'pallet', palletId:pid }; v.castShadow = true; group.add(v);
      });
      // 내부 수직 메시 빔 (248 간격 3개)
      const vCount = 3;
      const vSpacing = sW / (vCount + 1);
      for (let i = 1; i <= vCount; i++) {
        const vz = -sW/2 + vSpacing * i;
        const vm = new THREE.Mesh(new THREE.BoxGeometry(wallT * 0.7, wallH2, wallT), meshMat);
        vm.position.set(wx, baseH + wallH2/2, vz);
        vm.userData = { type:'pallet', palletId:pid }; vm.castShadow = true; group.add(vm);
      }
      // 내부 수평 메시 빔 (430×2)
      [baseH + wallH2 * 430/920, baseH + wallH2 * 860/920].forEach(hy => {
        const hm = new THREE.Mesh(new THREE.BoxGeometry(wallT * 0.7, wallT * 0.7, sW), meshMat);
        hm.position.set(wx, hy, 0);
        hm.userData = { type:'pallet', palletId:pid }; hm.castShadow = true; group.add(hm);
      });
      // 상부 스토퍼 (코너 고리)
      [-sW/2 + 50, sW/2 - 50].forEach(vz => {
        const hook = new THREE.Mesh(new THREE.BoxGeometry(pT2*1.5, pT2*2, pT2*1.5), topRailMat);
        hook.position.set(wx, baseH + wallH2 + pT2, vz);
        hook.userData = { type:'pallet', palletId:pid }; hook.castShadow = true; group.add(hook);
      });
    });

    // ── 4. 상단 연결 앵글 (면판+측판 상단 코너 연결) ──
    const aT = pT2;
    [-pD/2 - aT/2, pD/2 + aT/2].forEach(az => {
      const a = new THREE.Mesh(new THREE.BoxGeometry(pW + aT*2, aT, aT), topRailMat);
      a.position.set(0, baseH + wallH2 + aT/2, az);
      a.userData = { type:'pallet', palletId:pid }; a.castShadow = true; group.add(a);
    });
    [-pW/2 - aT/2, pW/2 + aT/2].forEach(ax => {
      const a = new THREE.Mesh(new THREE.BoxGeometry(aT, aT, pD + aT*2), topRailMat);
      a.position.set(ax, baseH + wallH2 + aT/2, 0);
      a.userData = { type:'pallet', palletId:pid }; a.castShadow = true; group.add(a);
    });

  }

  // ── 금호 카톤 파렛트 ──────────────────────────────────────────
  else if (type === 'karton') {
    // 1433×1100×110mm — 상부 데크판 + 하부 프레임 (벽 없음)
    const fMat = createMetalMaterial(0x8a9eab, 0.35, 0.88);
    const dMat = createMetalMaterial(0x7a8e9a, 0.45, 0.80);
    const bT = 30;

    // 하부 프레임 (도면 02/13 기준: 1430×1090)
    // 외곽 가로빔
    [-D/2+bT/2, D/2-bT/2].forEach(bz => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(W, bT, bT), fMat, pid, bT/2);
      m.position.z = bz;
    });
    // 외곽 세로빔
    [-W/2+bT/2, W/2-bT/2].forEach(bx => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(bT, bT, D), fMat, pid, bT/2);
      m.position.x = bx;
    });
    // 중간 세로빔 2개 (433-504-433)
    [-W/2 + W*433/1430, W/2 - W*433/1430].forEach(bx => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(bT, bT, D), fMat, pid, bT/2);
      m.position.x = bx;
    });
    // 중간 가로빔 2개 (305 간격)
    [-D/2 + D*305/1090, D/2 - D*305/1090].forEach(bz => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(W, bT*0.7, bT*0.7), fMat, pid, bT*0.35);
      m.position.z = bz;
    });
    // 지게차 진입 발 (코너 + 중간)
    const legH = H - bT, legT = bT*1.3;
    [[-W/2+legT/2,-D/2+legT/2],[W/2-legT/2,-D/2+legT/2],
     [-W/2+legT/2, D/2-legT/2],[W/2-legT/2, D/2-legT/2],
     [-W/2+W*433/1430,-D/2+legT/2],[ W/2-W*433/1430,-D/2+legT/2],
     [-W/2+W*433/1430, D/2-legT/2],[ W/2-W*433/1430, D/2-legT/2]
    ].forEach(([lx,lz]) => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(legT, legH, legT), fMat, pid, legH/2);
      m.position.x = lx; m.position.z = lz;
    });

    // 상부 앵글 프레임 (1433×1100)
    const aT = 20;
    [-D/2-aT/2, D/2+aT/2].forEach(az => {
      const a = new THREE.Mesh(new THREE.BoxGeometry(W+aT*2, aT, aT), fMat);
      a.position.set(0, H+aT/2, az);
      a.userData={type:'pallet',palletId:pid}; a.castShadow=true; group.add(a);
    });
    [-W/2-aT/2, W/2+aT/2].forEach(ax => {
      const a = new THREE.Mesh(new THREE.BoxGeometry(aT, aT, D+aT*2), fMat);
      a.position.set(ax, H+aT/2, 0);
      a.userData={type:'pallet',palletId:pid}; a.castShadow=true; group.add(a);
    });

    // 상부 데크판 (180mm 폭 패널 6장 — 도면 12/13)
    const panelW = W / 8; // 약 180mm
    const panelGap = W * 61/1433;
    for (let i = 0; i < 6; i++) {
      const px = -W/2 + W*30/1433 + (panelW + panelGap)*i + panelW/2;
      const deck = new THREE.Mesh(new THREE.BoxGeometry(panelW, 8, D), dMat);
      deck.position.set(px, H + aT + 4, 0);
      deck.userData={type:'pallet',palletId:pid}; deck.castShadow=true; group.add(deck);
    }
  }

  // ── 롯데 메시 파렛트 ──────────────────────────────────────────
  else if (type === 'lotte_mesh') {
    // 파렛트: 1443×1110, 면판: 1417×897, 측판: 1110×897
    const fMat  = createMetalMaterial(0x8a9eab, 0.32, 0.88);
    const mMat  = createMetalMaterial(0x7a8e9a, 0.48, 0.78);
    const tMat  = createMetalMaterial(0x9aaebb, 0.28, 0.92);
    const wallT = 15, bT = 30;
    const baseH = H, wallH2 = WH;

    // 하부 프레임 (도면 01/06: 1443×1110, 하부빔+블럭)
    // 외곽빔
    [-D/2+bT/2, D/2-bT/2].forEach(bz => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(W, bT, bT), fMat, pid, bT/2);
      m.position.z = bz;
    });
    [-W/2+bT/2, W/2-bT/2].forEach(bx => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(bT, bT, D), fMat, pid, bT/2);
      m.position.x = bx;
    });
    // 중간빔 (430-523-430)
    [-W/2+W*430/1443, W/2-W*430/1443].forEach(bx => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(bT, bT, D), fMat, pid, bT/2);
      m.position.x = bx;
    });
    // 블럭 (도면 02/06: 441 간격 3열)
    const blkH = baseH - bT, blkT = 30;
    [0, -W*441/1443, W*441/1443].forEach(bx => {
      [-D/2+blkT/2, D/2-blkT/2].forEach(bz => {
        const m = addPalletMesh(group, new THREE.BoxGeometry(blkT*3, blkH, blkT*3), fMat, pid, blkH/2);
        m.position.x = bx; m.position.z = bz;
      });
    });

    // 상부 프레임 (도면 03/06: 1443×1080)
    const sfT = 15;
    [-D/2+sfT/2, D/2-sfT/2].forEach(sz => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(W, sfT*2, sfT), fMat, pid, baseH+sfT);
      m.position.z = sz;
    });
    [-W/2+sfT/2, W/2-sfT/2].forEach(sx => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(sfT, sfT*2, D), fMat, pid, baseH+sfT);
      m.position.x = sx;
    });
    [0, -W*433/1443, W*433/1443].forEach(sx => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(sfT, sfT*2, D), fMat, pid, baseH+sfT);
      m.position.x = sx;
    });
    [-D/2+D*438/1110, D/2-D*438/1110].forEach(sz => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(W, sfT, sfT), fMat, pid, baseH+sfT*1.5);
      m.position.z = sz;
    });

    // 앵글+데크판 (도면 04/06)
    const aT2 = 20;
    const deck2 = new THREE.Mesh(new THREE.BoxGeometry(W-aT2*2, 5, D-aT2*2), mMat);
    deck2.position.set(0, baseH + sfT*2 + 3, 0);
    deck2.userData={type:'pallet',palletId:pid}; deck2.castShadow=true; group.add(deck2);
    [-D/2-aT2/2, D/2+aT2/2].forEach(az => {
      const a = new THREE.Mesh(new THREE.BoxGeometry(W+aT2*2, aT2, aT2), tMat);
      a.position.set(0, baseH+sfT*2+aT2/2, az);
      a.userData={type:'pallet',palletId:pid}; a.castShadow=true; group.add(a);
    });
    [-W/2-aT2/2, W/2+aT2/2].forEach(ax => {
      const a = new THREE.Mesh(new THREE.BoxGeometry(aT2, aT2, D+aT2*2), tMat);
      a.position.set(ax, baseH+sfT*2+aT2/2, 0);
      a.userData={type:'pallet',palletId:pid}; a.castShadow=true; group.add(a);
    });

    // 면판 앞/뒤 (1417×897 — 도면 06/06)
    const faceW = W * 1357/1443;
    [-D/2-wallT/2, D/2+wallT/2].forEach(wz => {
      // 외곽 프레임
      const top = new THREE.Mesh(new THREE.BoxGeometry(faceW, 20, 20), tMat);
      top.position.set(0, baseH+wallH2-10, wz);
      top.userData={type:'pallet',palletId:pid}; top.castShadow=true; group.add(top);
      const bot = new THREE.Mesh(new THREE.BoxGeometry(faceW, wallT, wallT), fMat);
      bot.position.set(0, baseH+wallT/2, wz);
      bot.userData={type:'pallet',palletId:pid}; bot.castShadow=true; group.add(bot);
      [-faceW/2+wallT/2, faceW/2-wallT/2].forEach(vx => {
        const v = new THREE.Mesh(new THREE.BoxGeometry(wallT, wallH2, wallT), fMat);
        v.position.set(vx, baseH+wallH2/2, wz);
        v.userData={type:'pallet',palletId:pid}; v.castShadow=true; group.add(v);
      });
      // 내부 수직빔 4개 (260-259-259-260 간격)
      [1,2,3,4].forEach(i => {
        const vx = -faceW/2 + faceW/5*i;
        const vm = new THREE.Mesh(new THREE.BoxGeometry(wallT*0.7, wallH2, wallT*0.7), mMat);
        vm.position.set(vx, baseH+wallH2/2, wz);
        vm.userData={type:'pallet',palletId:pid}; vm.castShadow=true; group.add(vm);
      });
      // 수평빔 중간 1개
      const hm = new THREE.Mesh(new THREE.BoxGeometry(faceW, wallT*0.7, wallT*0.7), mMat);
      hm.position.set(0, baseH+wallH2/2, wz);
      hm.userData={type:'pallet',palletId:pid}; hm.castShadow=true; group.add(hm);
    });

    // 측판 좌/우 (1110×897 — 도면 05/06)
    const sideW = D * 1050/1110;
    [-W/2-wallT/2, W/2+wallT/2].forEach(wx => {
      const top = new THREE.Mesh(new THREE.BoxGeometry(20, 20, sideW), tMat);
      top.position.set(wx, baseH+wallH2-10, 0);
      top.userData={type:'pallet',palletId:pid}; top.castShadow=true; group.add(top);
      const bot = new THREE.Mesh(new THREE.BoxGeometry(wallT, wallT, sideW), fMat);
      bot.position.set(wx, baseH+wallT/2, 0);
      bot.userData={type:'pallet',palletId:pid}; bot.castShadow=true; group.add(bot);
      [-sideW/2+wallT/2, sideW/2-wallT/2].forEach(vz => {
        const v = new THREE.Mesh(new THREE.BoxGeometry(wallT, wallH2, wallT), fMat);
        v.position.set(wx, baseH+wallH2/2, vz);
        v.userData={type:'pallet',palletId:pid}; v.castShadow=true; group.add(v);
      });
      [1,2,3].forEach(i => {
        const vz = -sideW/2 + sideW/4*i;
        const vm = new THREE.Mesh(new THREE.BoxGeometry(wallT*0.7, wallH2, wallT*0.7), mMat);
        vm.position.set(wx, baseH+wallH2/2, vz);
        vm.userData={type:'pallet',palletId:pid}; vm.castShadow=true; group.add(vm);
      });
      const hm = new THREE.Mesh(new THREE.BoxGeometry(wallT*0.7, wallT*0.7, sideW), mMat);
      hm.position.set(wx, baseH+wallH2/2, 0);
      hm.userData={type:'pallet',palletId:pid}; hm.castShadow=true; group.add(hm);
    });
  }

  // ── 롯데 프레임 파렛트 ────────────────────────────────────────
  else if (type === 'lotte_frame') {
    // 1440×1107×125mm — 하부+블럭+상부 격자 프레임
    const fMat  = createMetalMaterial(0x8a9eab, 0.32, 0.88);
    const fMat2 = createMetalMaterial(0x6a8090, 0.40, 0.85);
    const tMat  = createMetalMaterial(0x9aaebb, 0.28, 0.92);
    const bT = 30, sfT = 15;
    const baseH = H;

    // 하부 프레임 (도면 01/04: 1440×1107)
    [-D/2+bT/2, D/2-bT/2].forEach(bz => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(W, bT, bT), fMat, pid, bT/2);
      m.position.z = bz;
    });
    [-W/2+bT/2, W/2-bT/2].forEach(bx => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(bT, bT, D), fMat, pid, bT/2);
      m.position.x = bx;
    });
    // 중간빔 (460-460-460)
    [-W/2+W*460/1440, W/2-W*460/1440].forEach(bx => {
      const m = addPalletMesh(group, new THREE.BoxGeometry(bT, bT, D), fMat, pid, bT/2);
      m.position.x = bx;
    });
    // 블럭 (도면 02/04: 435-450-435)
    const blkH = baseH - bT, blkT = 30;
    [-W/2+W*435/1440, 0, W/2-W*435/1440].forEach(bx => {
      [-D/2+blkT*1.5, D/2-blkT*1.5].forEach(bz => {
        const m = addPalletMesh(group, new THREE.BoxGeometry(blkT*2.5, blkH, blkT*2.5), fMat, pid, blkH/2);
        m.position.x = bx; m.position.z = bz;
      });
    });

    // 상부 프레임 — 격자형 (도면 03/04: 1410.5×841.5)
    // 가로 메인빔 4개
    [-D/2+sfT*3, -D/2+D*413/1107, D/2-D*413/1107, D/2-sfT*3].forEach(sz => {
      const m = new THREE.Mesh(new THREE.BoxGeometry(W, sfT*2, sfT), fMat2);
      m.position.set(0, baseH+sfT, sz);
      m.userData={type:'pallet',palletId:pid}; m.castShadow=true; group.add(m);
    });
    // 세로 메인빔 4개
    [-W/2+sfT*3, -W/2+W*409/1410, W/2-W*409/1410, W/2-sfT*3].forEach(sx => {
      const m = new THREE.Mesh(new THREE.BoxGeometry(sfT, sfT*2, D), fMat2);
      m.position.set(sx, baseH+sfT, 0);
      m.userData={type:'pallet',palletId:pid}; m.castShadow=true; group.add(m);
    });
    // 외곽 마감빔
    [-D/2-sfT/2, D/2+sfT/2].forEach(sz => {
      const m = new THREE.Mesh(new THREE.BoxGeometry(W+sfT*2, sfT, sfT), fMat);
      m.position.set(0, baseH+sfT*0.5, sz);
      m.userData={type:'pallet',palletId:pid}; m.castShadow=true; group.add(m);
    });

    // 앵글+데크판 (도면 04/04: 1458×1120)
    const aT3 = 20;
    const deck3 = new THREE.Mesh(new THREE.BoxGeometry(W-aT3, 5, D-aT3), fMat2);
    deck3.position.set(0, baseH + sfT*2 + 3, 0);
    deck3.userData={type:'pallet',palletId:pid}; deck3.castShadow=true; group.add(deck3);
    [-D/2-aT3/2, D/2+aT3/2].forEach(az => {
      const a = new THREE.Mesh(new THREE.BoxGeometry(W+aT3*2, aT3, aT3), tMat);
      a.position.set(0, baseH+sfT*2+aT3/2, az);
      a.userData={type:'pallet',palletId:pid}; a.castShadow=true; group.add(a);
    });
    [-W/2-aT3/2, W/2+aT3/2].forEach(ax => {
      const a = new THREE.Mesh(new THREE.BoxGeometry(aT3, aT3, D+aT3*2), tMat);
      a.position.set(ax, baseH+sfT*2+aT3/2, 0);
      a.userData={type:'pallet',palletId:pid}; a.castShadow=true; group.add(a);
    });
  }

  // ── 모드온 메시 파렛트 (도면 03~06/06) ──────────────────────────
  else if (type === 'modeon') {
    const mBase  = createMetalMaterial(0x6a7a88, 0.42, 0.82);
    const mFrame = createMetalMaterial(0x8a9aaa, 0.34, 0.80);
    const mLight = createMetalMaterial(0xaabbc8, 0.28, 0.78);
    const mDeck2 = createMetalMaterial(0x78909a, 0.50, 0.65);
    const mWall  = createMetalMaterial(0x9aaebb, 0.30, 0.82);

    function mb(geo, mat, px, py, pz) {
      const m = new THREE.Mesh(geo, mat);
      m.castShadow = true; m.receiveShadow = true;
      m.position.set(px, py, pz);
      m.userData = { type:'pallet', palletId: pid };
      // 엣지라인
      const el = new THREE.LineSegments(
        new THREE.EdgesGeometry(geo),
        new THREE.LineBasicMaterial({ color:0x344050, transparent:true, opacity:0.35 })
      );
      m.add(el);
      group.add(m);
      return m;
    }

    const lf = 15; // 하판 각관 두께

    // ── 하판 (도면 04/06) 15×15 각관 ──
    // 외곽 X빔 (1380mm)
    mb(new THREE.BoxGeometry(W-lf*2, lf, lf), mBase, 0, lf/2, -D/2+lf/2);
    mb(new THREE.BoxGeometry(W-lf*2, lf, lf), mBase, 0, lf/2,  D/2-lf/2);
    // 외곽 Z빔 (1090mm)
    mb(new THREE.BoxGeometry(lf, lf, D), mBase, -W/2+lf/2, lf/2, 0);
    mb(new THREE.BoxGeometry(lf, lf, D), mBase,  W/2-lf/2, lf/2, 0);
    // 중간 X빔 2개 (275mm 간격)
    [-240, 240].forEach(zp => {
      mb(new THREE.BoxGeometry(W-lf*2, lf, lf), mBase, 0, lf/2, zp);
    });
    // 중간 Z빔 (480mm 위치)
    mb(new THREE.BoxGeometry(lf, lf, D), mBase, -480/2+lf/2, lf/2, 0);
    mb(new THREE.BoxGeometry(lf, lf, D), mBase,  480/2-lf/2, lf/2, 0);

    // ── 블럭 (도면 03/06) 15×30×80 ──
    const BH = 80, blkW = 30, blkD2 = 15;
    const BY = lf;
    // 4열 × 전후 2줄 = 8개 (15×30×80)
    [-W/2+30, -W/2+450, W/2-450, W/2-30].forEach(bx => {
      [-D/2+lf, D/2-lf].forEach(bz => {
        mb(new THREE.BoxGeometry(blkW, BH, blkD2), mFrame, bx, BY+BH/2, bz);
      });
    });
    // 중간 보강 블럭 (15×15×80) 8개
    [-W/2+30, -W/2+450, W/2-450, W/2-30].forEach(bx => {
      [-240, 240].forEach(bz => {
        mb(new THREE.BoxGeometry(lf, BH, lf), mFrame, bx, BY+BH/2, bz);
      });
    });

    const TY = BY + BH; // 상판 시작 Y

    // ── 상판 (도면 05/06) 30×15×1430 ──
    const tp = 30, ts = 15;
    // 외곽 X빔 30×15 2개 (앞뒤, 길이 1430)
    mb(new THREE.BoxGeometry(W, tp, ts), mLight, 0, TY+tp/2, -D/2+ts/2);
    mb(new THREE.BoxGeometry(W, tp, ts), mLight, 0, TY+tp/2,  D/2-ts/2);
    // 내부 Z빔 15×15×480 2개
    mb(new THREE.BoxGeometry(ts, ts, 480), mFrame, -530/2, TY+ts/2, 0);
    mb(new THREE.BoxGeometry(ts, ts, 480), mFrame,  530/2, TY+ts/2, 0);
    // 내부 X빔 15×15×1430 2개
    mb(new THREE.BoxGeometry(W, ts, ts), mFrame, 0, TY+ts/2, -240);
    mb(new THREE.BoxGeometry(W, ts, ts), mFrame, 0, TY+ts/2,  240);
    // 연결 세로빔 30×15×260 4개
    [[-530/2, -D/2+130], [-530/2, D/2-130], [530/2, -D/2+130], [530/2, D/2-130]].forEach(([xp,zp]) => {
      mb(new THREE.BoxGeometry(ts, tp, 260), mLight, xp, TY+tp/2, zp);
    });

    const DY2 = TY + tp; // 데크판 Y

    // ── 데크판 (도면 06/06) 1050×(180/140)×0.4T ──
    const dkT = 4;
    // 180mm 폭 2장 (중앙)
    mb(new THREE.BoxGeometry(180, dkT, D), mDeck2, -(80+180)/2, DY2+dkT/2, 0);
    mb(new THREE.BoxGeometry(180, dkT, D), mDeck2,  (80+180)/2, DY2+dkT/2, 0);
    // 140mm 폭 2장 (양쪽)
    mb(new THREE.BoxGeometry(140, dkT, D), mDeck2, -(80+180+335/2+70), DY2+dkT/2, 0);
    mb(new THREE.BoxGeometry(140, dkT, D), mDeck2,  (80+180+335/2+70), DY2+dkT/2, 0);
    // 끝 마감 20mm
    mb(new THREE.BoxGeometry(20, dkT, D), mDeck2, -W/2+10, DY2+dkT/2, 0);
    mb(new THREE.BoxGeometry(20, dkT, D), mDeck2,  W/2-10, DY2+dkT/2, 0);

    const WBOT = DY2 + dkT; // 벽 시작

    // ── 면판 (도면 02/02) 1400×620 ──
    const FW2 = 1340, FH2 = WH, Fst = 20;
    [-1, 1].forEach(side => {
      const fz = side * (D/2 + Fst/2);
      // 상단 빔 20×20
      mb(new THREE.BoxGeometry(FW2, Fst, Fst), mLight, 0, WBOT+FH2-Fst/2, fz);
      // 하단 빔 15×15
      mb(new THREE.BoxGeometry(FW2, lf, lf), mBase, 0, WBOT+lf/2, fz);
      // 좌우 수직빔 15×15
      mb(new THREE.BoxGeometry(lf, FH2, lf), mBase, -FW2/2, WBOT+FH2/2, fz);
      mb(new THREE.BoxGeometry(lf, FH2, lf), mBase,  FW2/2, WBOT+FH2/2, fz);
      // 내부 수직빔 4개 (312.5mm 간격)
      [-FW2/2+312.5, -FW2/2+625, -FW2/2+937.5].forEach(xp => {
        mb(new THREE.BoxGeometry(lf, FH2-Fst, 30), mFrame, xp, WBOT+(FH2-Fst)/2, fz);
      });
      // 수평 메시빔 2개
      [FH2*0.35, FH2*0.65].forEach(yp => {
        mb(new THREE.BoxGeometry(FW2-lf*2, lf, 30), mFrame, 0, WBOT+yp, fz);
      });
    });

    // ── 측판(좌/우) 도면 01/02: 1044×620 ──
    const SW2 = 1044, SH2 = WH, Sst = 20;
    [-1, 1].forEach(side => {
      const sx = side * (W/2 + Sst/2);
      // 상단 빔 20×20
      mb(new THREE.BoxGeometry(Sst, Sst, SW2), mLight, sx, WBOT+SH2-Sst/2, 0);
      // 하단 빔 15×15
      mb(new THREE.BoxGeometry(lf, lf, SW2), mBase, sx, WBOT+lf/2, 0);
      // 전후 수직빔 15×15
      mb(new THREE.BoxGeometry(lf, SH2, lf), mBase, sx, WBOT+SH2/2, -SW2/2);
      mb(new THREE.BoxGeometry(lf, SH2, lf), mBase, sx, WBOT+SH2/2,  SW2/2);
      // 내부 세로빔 3개 (250, 484, 250 분할)
      [-SW2/2+250, 0, SW2/2-250].forEach(zp => {
        mb(new THREE.BoxGeometry(Sst, SH2-Sst, lf), mFrame, sx, WBOT+(SH2-Sst)/2, zp);
      });
      // 내부 수평빔 2개
      [SH2*0.37, SH2*0.67].forEach(yp => {
        mb(new THREE.BoxGeometry(25, 13, SW2-lf*2), mFrame, sx, WBOT+yp, 0);
      });
      // 코너 보강 30×30 블럭
      [-SW2/2+235/2, SW2/2-235/2].forEach(zp => {
        mb(new THREE.BoxGeometry(Sst, 30, 235), mBase, sx, WBOT+15, zp);
      });
    });

    // 상단 연결 앵글 (면판+측판 상단 코너 연결)
    const topAngH = WBOT + WH;
    mb(new THREE.BoxGeometry(W+Sst*2, Fst, Fst), mLight, 0, topAngH-Fst/2, -D/2-Sst/2);
    mb(new THREE.BoxGeometry(W+Sst*2, Fst, Fst), mLight, 0, topAngH-Fst/2,  D/2+Sst/2);
    mb(new THREE.BoxGeometry(Fst, Fst, D+Sst*2), mLight, -W/2-Sst/2, topAngH-Fst/2, 0);
    mb(new THREE.BoxGeometry(Fst, Fst, D+Sst*2), mLight,  W/2+Sst/2, topAngH-Fst/2, 0);
  }

  // ── 모드온 솔리드 파렛트 (이미지 기준: 솔리드 면판+측판) ────────────
  else if (type === 'modeon_solid') {
    const mBase  = createMetalMaterial(0x5a6a78, 0.44, 0.84);
    const mFrame = createMetalMaterial(0x7a8a9a, 0.36, 0.82);
    const mLight = createMetalMaterial(0x9aaab8, 0.28, 0.80);
    const mDk    = createMetalMaterial(0x6a7a86, 0.52, 0.68);
    const mPanel = createMetalMaterial(0x8898a8, 0.38, 0.76);

    // 엣지라인 포함 mesh 생성 헬퍼
    function mb2(geo, mat, px, py, pz, ry) {
      const m = new THREE.Mesh(geo, mat);
      m.castShadow = true; m.receiveShadow = true;
      m.position.set(px, py, pz);
      if (ry) m.rotation.y = ry;
      m.userData = { type:'pallet', palletId: pid };
      const el = new THREE.LineSegments(
        new THREE.EdgesGeometry(geo),
        new THREE.LineBasicMaterial({ color:0x2a3848, transparent:true, opacity:0.4 })
      );
      m.add(el);
      group.add(m);
      return m;
    }

    const lf = 15; // 기본 각관 두께

    [-D/2+lf/2, 0, D/2-lf/2].forEach(zp => {
      mb2(new THREE.BoxGeometry(W, lf, lf), mBase, 0, lf/2, zp);
    });
    // 가로빔 (Z방향) 3개
    [-W/2+lf/2, 0, W/2-lf/2].forEach(xp => {
      mb2(new THREE.BoxGeometry(lf, lf, D), mBase, xp, lf/2, 0);
    });
    // 중간 보강빔
    [-W/4, W/4].forEach(xp => {
      mb2(new THREE.BoxGeometry(lf, lf, D), mBase, xp, lf/2, 0);
    });
    [-D/4, D/4].forEach(zp => {
      mb2(new THREE.BoxGeometry(W, lf, lf), mBase, 0, lf/2, zp);
    });

    // ══ 2단계: 하부앵글 (외곽 프레임 + 내부 격자) ══
    // 외곽 각관 프레임
    const aT = 20;
    mb2(new THREE.BoxGeometry(W, aT, aT), mFrame, 0, lf+aT/2, -D/2+aT/2);
    mb2(new THREE.BoxGeometry(W, aT, aT), mFrame, 0, lf+aT/2,  D/2-aT/2);
    mb2(new THREE.BoxGeometry(aT, aT, D), mFrame, -W/2+aT/2, lf+aT/2, 0);
    mb2(new THREE.BoxGeometry(aT, aT, D), mFrame,  W/2-aT/2, lf+aT/2, 0);
    // 내부 격자빔 (가로 3줄)
    [-W/4, 0, W/4].forEach(xp => {
      mb2(new THREE.BoxGeometry(aT, aT, D-aT*2), mFrame, xp, lf+aT/2, 0);
    });
    // 내부 격자빔 (세로 2줄)
    [-D/4, D/4].forEach(zp => {
      mb2(new THREE.BoxGeometry(W-aT*2, aT, aT), mFrame, 0, lf+aT/2, zp);
    });

    // ══ 3단계: 블럭 (상단 돌출 블럭) ══
    const BH = 80, blkS = 30;
    const BY = lf + aT;
    // 외곽 4코너 + 중간 5개 = 9개 블럭
    [
      [-W/2+blkS, -D/2+blkS], [0, -D/2+blkS], [W/2-blkS, -D/2+blkS],
      [-W/2+blkS, 0],          [0, 0],          [W/2-blkS, 0],
      [-W/2+blkS,  D/2-blkS], [0,  D/2-blkS], [W/2-blkS,  D/2-blkS],
    ].forEach(([bx, bz]) => {
      mb2(new THREE.BoxGeometry(blkS, BH, blkS), mLight, bx, BY+BH/2, bz);
    });

    const TY = BY + BH; // 상판 시작 Y

    // ══ 4단계: 상부 상판 ══
    // 상부 외곽 프레임
    mb2(new THREE.BoxGeometry(W, aT, aT), mLight, 0, TY+aT/2, -D/2+aT/2);
    mb2(new THREE.BoxGeometry(W, aT, aT), mLight, 0, TY+aT/2,  D/2-aT/2);
    mb2(new THREE.BoxGeometry(aT, aT, D), mLight, -W/2+aT/2, TY+aT/2, 0);
    mb2(new THREE.BoxGeometry(aT, aT, D), mLight,  W/2-aT/2, TY+aT/2, 0);
    // 내부 가로 빔 4개 (이미지: 데크 방향 빔)
    [-D/2+D*1/5, -D/2+D*2/5, -D/2+D*3/5, -D/2+D*4/5].forEach(zp => {
      mb2(new THREE.BoxGeometry(W-aT*2, lf, lf*2), mFrame, 0, TY+lf, zp);
    });
    // 세로 보강빔 2개
    [-W/4, W/4].forEach(xp => {
      mb2(new THREE.BoxGeometry(lf, lf, D-aT*2), mFrame, xp, TY+lf, 0);
    });

    // ══ 5단계: 상부앵글 (상판 위 격자 앵글) ══
    const SA = TY + aT;
    mb2(new THREE.BoxGeometry(W+aT*2, lf, lf), mLight, 0, SA+lf/2, -D/2-aT/2);
    mb2(new THREE.BoxGeometry(W+aT*2, lf, lf), mLight, 0, SA+lf/2,  D/2+aT/2);
    mb2(new THREE.BoxGeometry(lf, lf, D+aT*2), mLight, -W/2-aT/2, SA+lf/2, 0);
    mb2(new THREE.BoxGeometry(lf, lf, D+aT*2), mLight,  W/2+aT/2, SA+lf/2, 0);

    // ══ 6단계: 데크판 (얇은 판재) ══
    const DY3 = SA + lf;
    const dkT2 = 3;
    // 가로 방향 데크판 5장 (이미지 기준)
    const dkW = (W - aT*2) / 5;
    for (let i = 0; i < 5; i++) {
      const xp = -W/2 + aT + dkW/2 + i*dkW;
      mb2(new THREE.BoxGeometry(dkW - 3, dkT2, D - aT*2), mDk, xp, DY3 + dkT2/2, 0);
    }

    const WBOT = DY3 + dkT2; // 벽 시작 Y

    const FW3 = W - aT*2, FH3 = WH, pnlT = 8;
    [-1, 1].forEach(side => {
      const fz = side * (D/2 + aT/2);
      // 솔리드 판
      mb2(new THREE.BoxGeometry(FW3, FH3, pnlT), mPanel, 0, WBOT + FH3/2, fz);
      // 상단 마감 각관
      mb2(new THREE.BoxGeometry(FW3 + aT*2, aT, aT), mLight, 0, WBOT+FH3-aT/2, fz);
      // 하단 각관
      mb2(new THREE.BoxGeometry(FW3 + aT*2, aT, aT), mFrame, 0, WBOT+aT/2, fz);
      // 좌우 수직 각관
      mb2(new THREE.BoxGeometry(aT, FH3, aT), mFrame, -FW3/2-aT/2, WBOT+FH3/2, fz);
      mb2(new THREE.BoxGeometry(aT, FH3, aT), mFrame,  FW3/2+aT/2, WBOT+FH3/2, fz);
      // 내부 수직 분할 각관 2개 (이미지: 3분할)
      [-FW3/3, FW3/3].forEach(xp => {
        mb2(new THREE.BoxGeometry(aT, FH3, aT*0.7), mFrame, xp, WBOT+FH3/2, fz);
      });
    });

    // ══ 8단계: 측판 (솔리드 + 프레임 — 최종완성) ══
    const SW3 = D - aT*2, SH3 = WH;
    [-1, 1].forEach(side => {
      const sx = side * (W/2 + aT/2);
      // 솔리드 판
      mb2(new THREE.BoxGeometry(pnlT, SH3, SW3), mPanel, sx, WBOT + SH3/2, 0);
      // 상단 각관
      mb2(new THREE.BoxGeometry(aT, aT, SW3 + aT*2), mLight, sx, WBOT+SH3-aT/2, 0);
      // 하단 각관
      mb2(new THREE.BoxGeometry(aT, aT, SW3 + aT*2), mFrame, sx, WBOT+aT/2, 0);
      // 전후 수직 각관
      mb2(new THREE.BoxGeometry(aT, SH3, aT), mFrame, sx, WBOT+SH3/2, -SW3/2-aT/2);
      mb2(new THREE.BoxGeometry(aT, SH3, aT), mFrame, sx, WBOT+SH3/2,  SW3/2+aT/2);
      // 내부 수직 분할 각관 1개 (이미지: 2분할)
      mb2(new THREE.BoxGeometry(aT*0.7, SH3, aT), mFrame, sx, WBOT+SH3/2, 0);
    });

    // 최상단 코너 연결 캡
    [[W/2+aT/2, WBOT+WH-aT/2, D/2+aT/2],
     [W/2+aT/2, WBOT+WH-aT/2,-D/2-aT/2],
     [-W/2-aT/2,WBOT+WH-aT/2, D/2+aT/2],
     [-W/2-aT/2,WBOT+WH-aT/2,-D/2-aT/2]].forEach(([cx,cy,cz]) => {
      mb2(new THREE.BoxGeometry(aT*1.2, aT*1.2, aT*1.2), mLight, cx, cy, cz);
    });
  }

  // ── 수평 드럼 파렛트 2롤 ──────────────────────────────────────────
  else if (type === 'drum_h') {
    // GLB 실측 geometry를 직접 렌더링
    const vB64 = ""

    const iB64 = ""

    function b64ToFloat32(b64) {
      const bin = atob(b64);
      const buf = new ArrayBuffer(bin.length);
      const view = new Uint8Array(buf);
      for (let i=0;i<bin.length;i++) view[i]=bin.charCodeAt(i);
      return new Float32Array(buf);
    }
    function b64ToInt32(b64) {
      const bin = atob(b64);
      const buf = new ArrayBuffer(bin.length);
      const view = new Uint8Array(buf);
      for (let i=0;i<bin.length;i++) view[i]=bin.charCodeAt(i);
      return new Int32Array(buf);
    }

    const verts = b64ToFloat32(vB64);
    const idxs  = b64ToInt32(iB64);

    const geo = new THREE.BufferGeometry();
    geo.setAttribute('position', new THREE.BufferAttribute(verts, 3));
    geo.setIndex(new THREE.BufferAttribute(new Uint32Array(idxs.buffer), 1));
    geo.computeVertexNormals();

    const mat = createMetalMaterial(0x7a8a9a, 0.36, 0.82);
    const mesh = new THREE.Mesh(geo, mat);
    mesh.castShadow = true; mesh.receiveShadow = true;
    mesh.userData = { type:'pallet', palletId: pid };

    // GLB 스케일: 원본이 mm 단위, 파렛트 파라미터 W/D와 맞춤
    // 원본: X=-543~543(1086mm), Y=0~314, Z=-348~348(696mm)
    // 파라미터: W=1430, D=1090 → 스케일 적용
    const scaleX = W / 1086;
    const scaleZ = D / 696;
    const scaleY = H / 314;
    mesh.scale.set(scaleX, scaleY, scaleZ);

    // 에지라인
    const edges = new THREE.LineSegments(
      new THREE.EdgesGeometry(geo),
      new THREE.LineBasicMaterial({color:0x1a2838, transparent:true, opacity:0.4})
    );
    mesh.add(edges);
    group.add(mesh);
  }

  else if (type === 'gamma2_mq4') {
    // ── 재질 ──
    const mBeam = createMetalMaterial(0x8a9eae, 0.28, 0.92);  // 메인 S/TUBE 빔
    const rBeam = createMetalMaterial(0x7a8e9c, 0.35, 0.88);  // 세로 런너
    const fgMat = createMetalMaterial(0x9a8c70, 0.45, 0.65);  // Fork Guide
    const brMat = createMetalMaterial(0x5e6e7e, 0.40, 0.82);  // 브라켓/플레이트

    // ── 치수 상수 ──
    // W=1440(X), D=2270(Z), H=baseH(150)
    const baseH = H;

    // 가로빔 단면: 70(Z두께) × 30(Y높이)
    const bZ = 70, bY2 = 30;
    // 세로 런너 길이: 2250 (양끝 10mm 여백)
    const rLen = 2250;

    const zFront = -D/2 + bZ/2;
    const zBack  =  D/2 - bZ/2;
    const zPositions = [
      { z: zFront,    len: W    },   // ① 전면
      { z: -D/4,      len: 1420 },   // ② 1/4 지점
      { z: 0,         len: 1420 },   // ③ 중앙
      { z:  D/4,      len: 1420 },   // ④ 3/4 지점
      { z: zBack,     len: 1420 },   // ⑤ 후면
    ];
    zPositions.forEach(({ z, len }) => {
      const m = new THREE.Mesh(new THREE.BoxGeometry(len, bY2, bZ), mBeam);
      m.position.set(0, bY2/2, z);
      m.userData={type:'pallet',palletId:pid}; m.castShadow=true; m.receiveShadow=true;
      group.add(m);
    });

    // ── 세로 런너 9개 ──
    // 양끝 2개: X = ±(W/2 - 15) 끝에 붙임 (30×30)
    // 나머지 7개: 그 사이를 6등분 균등 배치
    const r30 = 30;
    const r40w = 40, r40h = 20;

    const xLeft  = -(W/2 - r30/2);   // 좌끝 = -705
    const xRight =  (W/2 - r30/2);   // 우끝 = +705
    const gap = (xRight - xLeft) / 8; // 7개를 6등분 → 8구간 = 176.25mm

    const runnerXPos = [
      { x: xLeft,          w: r30,  h: r30  },  // ① 좌끝
      { x: xLeft + gap*1,  w: r40w, h: r40h },  // ②
      { x: xLeft + gap*2,  w: r30,  h: r30  },  // ③
      { x: xLeft + gap*3,  w: r40w, h: r40h },  // ④
      { x: 0,              w: r30,  h: r30  },  // ⑤ 중앙
      { x: xRight - gap*3, w: r40w, h: r40h },  // ⑥
      { x: xRight - gap*2, w: r30,  h: r30  },  // ⑦
      { x: xRight - gap*1, w: r40w, h: r40h },  // ⑧
      { x: xRight,         w: r30,  h: r30  },  // ⑨ 우끝
    ];

    runnerXPos.forEach(({ x, w, h }) => {
      const m = new THREE.Mesh(new THREE.BoxGeometry(w, h, rLen), rBeam);
      m.position.set(x, h/2, 0);
      m.userData={type:'pallet',palletId:pid}; m.castShadow=true; m.receiveShadow=true;
      group.add(m);
    });


    const fgW2 = 310, fgD2 = 50, fgT2 = 3;
    const fgZArr = [zFront + 250, zBack - 250];
    const fgXArr = [-(W/4), W/4];

    fgXArr.forEach(fx => {
      fgZArr.forEach(fz => {
        // ⑦ 베이스 플레이트 (310×50×3T) — 런너 위에 올림
        const plate = new THREE.Mesh(
          new THREE.BoxGeometry(fgW2, fgT2, fgD2), fgMat);
        plate.position.set(fx, 20 + fgT2/2, fz);
        plate.userData={type:'pallet',palletId:pid}; plate.castShadow=true; group.add(plate);

        // ⑥ Fork Guide D-K형 — 플레이트 위 U채널
        // 양쪽 립(Z방향 전후 벽): 높이=40, 두께=3
        const lipH = 40;
        [-fgD2/2 + fgT2/2, fgD2/2 - fgT2/2].forEach(oz => {
          const lip = new THREE.Mesh(
            new THREE.BoxGeometry(fgW2, lipH, fgT2), fgMat);
          lip.position.set(fx, 20 + fgT2 + lipH/2, fz + oz);
          lip.userData={type:'pallet',palletId:pid}; lip.castShadow=true; group.add(lip);
        });
      });
    });

    // ── ⑧ 하부 BRAK'T 100×40×2T ×2 ──
    // 중앙 세로빔(X=0)과 전후 가로빔 교차점 내측 보강
    [zFront, zBack].forEach(bz => {
      const br = new THREE.Mesh(new THREE.BoxGeometry(100, 40, 2), brMat);
      br.position.set(0, 20, bz + (bz < 0 ? bZ/2 + 1 : -(bZ/2 + 1)));
      br.userData={type:'pallet',palletId:pid}; br.castShadow=true; group.add(br);
    });

    // ── ⑨ 보강 브라켓/플레이트 ──
    // 50×30×3T: 4코너 런너-가로빔 연결부
    [-(W/2 - r30/2), W/2 - r30/2].forEach(bx => {
      [zFront, zBack].forEach(bz => {
        const br = new THREE.Mesh(new THREE.BoxGeometry(r30, 30, 3), brMat);
        br.position.set(bx, 15, bz + (bz < 0 ? bZ/2 + 1.5 : -(bZ/2 + 1.5)));
        br.userData={type:'pallet',palletId:pid}; br.castShadow=true; group.add(br);
      });
    });
    // 83×70×2.2T PLATE: Fork Guide 고정 (×4)
    fgXArr.forEach(fx => {
      fgZArr.forEach(fz => {
        const pl = new THREE.Mesh(new THREE.BoxGeometry(83, 2, 70), brMat);
        pl.position.set(fx, bY2 + 1, fz);
        pl.userData={type:'pallet',palletId:pid}; pl.castShadow=true; group.add(pl);
      });
    });



    const sH  = WH;       // 앞문 높이 800mm
    const sT  = 30;       // 빔 두께
    const sY0 = baseH;    // 앞문 하단 = 밑판 상단
    const fDoorZ = -D/2 - sT/2;  // 앞문 Z위치 (밑판 앞면 바깥)

    // ── 외곽 프레임 ──
    // 하단 수평빔
    const fdBot = new THREE.Mesh(new THREE.BoxGeometry(W, sT, sT), mBeam);
    fdBot.position.set(0, sY0 + sT/2, fDoorZ);
    fdBot.userData={type:'pallet',palletId:pid}; fdBot.castShadow=true; group.add(fdBot);
    // 상단 수평빔
    const fdTop = new THREE.Mesh(new THREE.BoxGeometry(W, sT, sT), mBeam);
    fdTop.position.set(0, sY0 + sH - sT/2, fDoorZ);
    fdTop.userData={type:'pallet',palletId:pid}; fdTop.castShadow=true; group.add(fdTop);
    // 좌 수직빔
    const fdVL = new THREE.Mesh(new THREE.BoxGeometry(sT, sH, sT), mBeam);
    fdVL.position.set(-W/2 + sT/2, sY0 + sH/2, fDoorZ);
    fdVL.userData={type:'pallet',palletId:pid}; fdVL.castShadow=true; group.add(fdVL);
    // 우 수직빔
    const fdVR = new THREE.Mesh(new THREE.BoxGeometry(sT, sH, sT), mBeam);
    fdVR.position.set(W/2 - sT/2, sY0 + sH/2, fDoorZ);
    fdVR.userData={type:'pallet',palletId:pid}; fdVR.castShadow=true; group.add(fdVR);

    const xDiv = -W/2 + Math.round(W * (1050/1800));  // = +120
    const fdVM = new THREE.Mesh(new THREE.BoxGeometry(sT, sH, sT), mBeam);
    fdVM.position.set(xDiv, sY0 + sH/2, fDoorZ);
    fdVM.userData={type:'pallet',palletId:pid}; fdVM.castShadow=true; group.add(fdVM);

    // ── 브레이스 — 좌구획 \ , 우구획 / ──
    const diag1W = W * (1050/1800);
    const diag1Len = Math.sqrt(diag1W**2 + sH**2);
    const diag1Ang = Math.atan2(sH, diag1W);
    const diag1CX = -W/2 + diag1W/2;

    // \ 좌상→우하
    const fd1 = new THREE.Mesh(new THREE.BoxGeometry(diag1Len, sT, sT), brMat);
    fd1.position.set(diag1CX, sY0 + sH/2, fDoorZ);
    fd1.rotation.z = -diag1Ang;
    fd1.userData={type:'pallet',palletId:pid}; fd1.castShadow=true; group.add(fd1);

    const diag2W = W * (750/1800);
    const diag2Len = Math.sqrt(diag2W**2 + sH**2);
    const diag2Ang = Math.atan2(sH, diag2W);
    const diag2CX = xDiv + diag2W/2;

    // / 좌하→우상
    const fd2 = new THREE.Mesh(new THREE.BoxGeometry(diag2Len, sT, sT), brMat);
    fd2.position.set(diag2CX, sY0 + sH/2, fDoorZ);
    fd2.rotation.z = diag2Ang;
    fd2.userData={type:'pallet',palletId:pid}; fd2.castShadow=true; group.add(fd2);

    // ── 상단 소형 브라켓 ③⑩⑤ ──
    [-W/4, xDiv, W/4].forEach(bx => {
      const bkt = new THREE.Mesh(new THREE.BoxGeometry(sT*0.8, sT*0.8, sT*1.5), brMat);
      bkt.position.set(bx, sY0 + sH + sT*0.4, fDoorZ);
      bkt.userData={type:'pallet',palletId:pid}; bkt.castShadow=true; group.add(bkt);
    });

    // ── 코너 브라켓 ⑨ (4코너) ──
    [-W/2 + sT, W/2 - sT].forEach(cx => {
      [sY0 + sT, sY0 + sH - sT].forEach(cy => {
        const ck = new THREE.Mesh(new THREE.BoxGeometry(sT*1.5, sT*0.6, sT*1.5), brMat);
        ck.position.set(cx, cy, fDoorZ);
        ck.userData={type:'pallet',palletId:pid}; ck.castShadow=true; group.add(ck);
      });
    });

    const spScale = D / 2550;
    const spW0 = 900 * spScale;  // 좌구획 너비
    const spW1 = 750 * spScale;  // 중간구획 너비
    const spW2 = 900 * spScale;  // 우구획 너비
    const spZ0 = -D/2;           // 패널 좌끝
    const spZ1 = spZ0 + spW0;    // 1번 수직빔 Z
    const spZ2 = spZ1 + spW1;    // 2번 수직빔 Z
    const spZ3 = D/2;            // 패널 우끝

    // 측판 생성 헬퍼 함수
    const buildSidePanel = (targetGroup, px) => {
      // ── 외곽 프레임 ──
      const spBot2 = new THREE.Mesh(new THREE.BoxGeometry(sT, sT, D), mBeam);
      spBot2.position.set(px, sY0 + sT/2, 0);
      spBot2.userData={type:'pallet',palletId:pid}; spBot2.castShadow=true; targetGroup.add(spBot2);

      const spTop2 = new THREE.Mesh(new THREE.BoxGeometry(sT, sT, D), mBeam);
      spTop2.position.set(px, sY0 + sH - sT/2, 0);
      spTop2.userData={type:'pallet',palletId:pid}; spTop2.castShadow=true; targetGroup.add(spTop2);

      // ── 수직빔 2개 + 대각선 ──
      const vz1 = -D/4, vz2 = D/4;
      [vz1, vz2].forEach(vz => {
        const vm = new THREE.Mesh(new THREE.BoxGeometry(sT, sH, sT), mBeam);
        vm.position.set(px, sY0 + sH/2, vz);
        vm.userData={type:'pallet',palletId:pid}; vm.castShadow=true; targetGroup.add(vm);
      });

      const dLen1 = Math.sqrt((D/4)**2 + sH**2);
      const dAng1 = Math.atan2(sH, D/4);

      const db1 = new THREE.Mesh(new THREE.BoxGeometry(sT, sT, dLen1), brMat);
      db1.position.set(px, sY0 + sH/2, (-D/2 + vz1) / 2);
      db1.rotation.x = dAng1;
      db1.userData={type:'pallet',palletId:pid}; db1.castShadow=true; targetGroup.add(db1);

      const db2 = new THREE.Mesh(new THREE.BoxGeometry(sT, sT, dLen1), brMat);
      db2.position.set(px, sY0 + sH/2, (D/2 + vz2) / 2);
      db2.rotation.x = -dAng1;
      db2.userData={type:'pallet',palletId:pid}; db2.castShadow=true; targetGroup.add(db2);

      const midW = (vz2 - vz1) / 2;
      const midLen = Math.sqrt(midW**2 + sH**2);
      const midAng = Math.atan2(sH, midW);

      const dm1 = new THREE.Mesh(new THREE.BoxGeometry(sT, sT, midLen), brMat);
      dm1.position.set(px, sY0 + sH/2, (vz1 + 0) / 2);
      dm1.rotation.x = -midAng;
      dm1.userData={type:'pallet',palletId:pid}; dm1.castShadow=true; targetGroup.add(dm1);

      const dm2 = new THREE.Mesh(new THREE.BoxGeometry(sT, sT, midLen), brMat);
      dm2.position.set(px, sY0 + sH/2, (0 + vz2) / 2);
      dm2.rotation.x = midAng;
      dm2.userData={type:'pallet',palletId:pid}; dm2.castShadow=true; targetGroup.add(dm2);

      // ── 코너 브라켓 ──
      [spZ0 + sT, spZ3 - sT].forEach(cz => {
        [sY0 + sT, sY0 + sH - sT].forEach(cy => {
          const ck = new THREE.Mesh(new THREE.BoxGeometry(sT*1.5, sT*0.6, sT*1.5), brMat);
          ck.position.set(px, cy, cz);
          ck.userData={type:'pallet',palletId:pid}; ck.castShadow=true; targetGroup.add(ck);
        });
      });
    };

    // 좌측판 — 그대로
    buildSidePanel(group, -W/2 - sT/2);

    // 우측판 — 가로 절반: 아래쪽(Y: sY0~sY0+sH/2) 세움, 위쪽(Y: sY0+sH/2~sY0+sH) 바깥으로 90도 접힘
    const rpx = W/2 + sT/2;

    // ── 아래쪽 절반 (세움) ──
    const rpBot2 = new THREE.Mesh(new THREE.BoxGeometry(sT, sT, D), mBeam);
    rpBot2.position.set(rpx, sY0 + sT/2, 0);
    rpBot2.userData={type:'pallet',palletId:pid}; rpBot2.castShadow=true; group.add(rpBot2);

    const rpMid = new THREE.Mesh(new THREE.BoxGeometry(sT, sT, D), mBeam);
    rpMid.position.set(rpx, sY0 + sH/2, 0);
    rpMid.userData={type:'pallet',palletId:pid}; rpMid.castShadow=true; group.add(rpMid);

    const rpVF_lo = new THREE.Mesh(new THREE.BoxGeometry(sT, sH/2, sT), mBeam);
    rpVF_lo.position.set(rpx, sY0 + sH/4, -D/2 + sT/2);
    rpVF_lo.userData={type:'pallet',palletId:pid}; rpVF_lo.castShadow=true; group.add(rpVF_lo);

    const rpVB_lo = new THREE.Mesh(new THREE.BoxGeometry(sT, sH/2, sT), mBeam);
    rpVB_lo.position.set(rpx, sY0 + sH/4, D/2 - sT/2);
    rpVB_lo.userData={type:'pallet',palletId:pid}; rpVB_lo.castShadow=true; group.add(rpVB_lo);

    // 아래 수직빔 2개
    [-D/4, D/4].forEach(vz => {
      const vm = new THREE.Mesh(new THREE.BoxGeometry(sT, sH/2, sT), mBeam);
      vm.position.set(rpx, sY0 + sH/4, vz);
      vm.userData={type:'pallet',palletId:pid}; vm.castShadow=true; group.add(vm);
    });

    // ── 위쪽 절반 — 힌지(Y=sY0+sH/2) 기준 바깥(X+)으로 90도 접힘 ──
    const topFoldPivot = new THREE.Group();
    topFoldPivot.position.set(rpx, sY0 + sH/2, 0);
    topFoldPivot.rotation.y = 0;
    // X축 기준 -90도: 위쪽이 바깥(X+)으로 눕힘
    topFoldPivot.rotation.z = -Math.PI / 2;
    group.add(topFoldPivot);

    const lx3 = 0;

    const rpTop2 = new THREE.Mesh(new THREE.BoxGeometry(sT, sT, D), mBeam);
    rpTop2.position.set(lx3, sH/2 - sT/2, 0);
    rpTop2.userData={type:'pallet',palletId:pid}; rpTop2.castShadow=true; topFoldPivot.add(rpTop2);

    const rpVF_hi = new THREE.Mesh(new THREE.BoxGeometry(sT, sH/2, sT), mBeam);
    rpVF_hi.position.set(lx3, sH/4, -D/2 + sT/2);
    rpVF_hi.userData={type:'pallet',palletId:pid}; rpVF_hi.castShadow=true; topFoldPivot.add(rpVF_hi);

    const rpVB_hi = new THREE.Mesh(new THREE.BoxGeometry(sT, sH/2, sT), mBeam);
    rpVB_hi.position.set(lx3, sH/4, D/2 - sT/2);
    rpVB_hi.userData={type:'pallet',palletId:pid}; rpVB_hi.castShadow=true; topFoldPivot.add(rpVB_hi);

    [-D/4, D/4].forEach(vz => {
      const vm = new THREE.Mesh(new THREE.BoxGeometry(sT, sH/2, sT), mBeam);
      vm.position.set(lx3, sH/4, vz);
      vm.userData={type:'pallet',palletId:pid}; vm.castShadow=true; topFoldPivot.add(vm);
    });

    // ── 뒷문 (Z+ 방향, 앞문과 동일 구조) ──
    const rDoorZ = D/2 + sT/2;

    // 외곽 프레임
    const rdBot = new THREE.Mesh(new THREE.BoxGeometry(W, sT, sT), mBeam);
    rdBot.position.set(0, sY0 + sT/2, rDoorZ);
    rdBot.userData={type:'pallet',palletId:pid}; rdBot.castShadow=true; group.add(rdBot);

    const rdTop = new THREE.Mesh(new THREE.BoxGeometry(W, sT, sT), mBeam);
    rdTop.position.set(0, sY0 + sH - sT/2, rDoorZ);
    rdTop.userData={type:'pallet',palletId:pid}; rdTop.castShadow=true; group.add(rdTop);

    const rdVL = new THREE.Mesh(new THREE.BoxGeometry(sT, sH, sT), mBeam);
    rdVL.position.set(-W/2 + sT/2, sY0 + sH/2, rDoorZ);
    rdVL.userData={type:'pallet',palletId:pid}; rdVL.castShadow=true; group.add(rdVL);

    const rdVR = new THREE.Mesh(new THREE.BoxGeometry(sT, sH, sT), mBeam);
    rdVR.position.set(W/2 - sT/2, sY0 + sH/2, rDoorZ);
    rdVR.userData={type:'pallet',palletId:pid}; rdVR.castShadow=true; group.add(rdVR);

    // 중앙 수직빔
    const rdVM = new THREE.Mesh(new THREE.BoxGeometry(sT, sH, sT), mBeam);
    rdVM.position.set(xDiv, sY0 + sH/2, rDoorZ);
    rdVM.userData={type:'pallet',palletId:pid}; rdVM.castShadow=true; group.add(rdVM);

    // 브레이스 \ /
    const rd1 = new THREE.Mesh(new THREE.BoxGeometry(diag1Len, sT, sT), brMat);
    rd1.position.set(diag1CX, sY0 + sH/2, rDoorZ);
    rd1.rotation.z = -diag1Ang;
    rd1.userData={type:'pallet',palletId:pid}; rd1.castShadow=true; group.add(rd1);

    const rd2 = new THREE.Mesh(new THREE.BoxGeometry(diag2Len, sT, sT), brMat);
    rd2.position.set(diag2CX, sY0 + sH/2, rDoorZ);
    rd2.rotation.z = diag2Ang;
    rd2.userData={type:'pallet',palletId:pid}; rd2.castShadow=true; group.add(rd2);

    // 코너 브라켓
    [-W/2 + sT, W/2 - sT].forEach(cx => {
      [sY0 + sT, sY0 + sH - sT].forEach(cy => {
        const ck = new THREE.Mesh(new THREE.BoxGeometry(sT*1.5, sT*0.6, sT*1.5), brMat);
        ck.position.set(cx, cy, rDoorZ);
        ck.userData={type:'pallet',palletId:pid}; ck.castShadow=true; group.add(ck);
      });
    });
  }

  // 총 높이 계산 (박스 적재용)
  const totalH = (type === 'flat') ? H : (type === 'octaframe') ? WH : H + WH;

  // Top surface for raycasting
  const topGeo = new THREE.BoxGeometry(W, 2, D);
  const topMat2 = new THREE.MeshStandardMaterial({ transparent: true, opacity: 0 });
  const topMesh = new THREE.Mesh(topGeo, topMat2);
  topMesh.position.set(0, type === 'octaframe' ? 0 : H, 0);
  topMesh.userData = { type: 'palletTop', palletId: pallet.id };
  group.add(topMesh);

  // Selection ring (전체 높이 기준)
  const ringH = (type === 'octaframe') ? WH : (type === 'flat') ? H : H + WH;
  const ringGeo = new THREE.EdgesGeometry(new THREE.BoxGeometry(W+20, ringH+20, D+20));
  const ringMat2 = new THREE.LineBasicMaterial({ color: 0x00d4ff, transparent: true, opacity: 0 });
  const ring = new THREE.LineSegments(ringGeo, ringMat2);
  ring.position.set(0, ringH/2, 0);
  ring.userData = { isSelectionRing: true };
  group.add(ring);

  group.position.set(pallet.posX, 0, pallet.posZ);
  scene.add(group);
  pallet.mesh = group;
  return group;
}

function highlightPallet(id) {
  pallets.forEach(p => {
    if (!p.mesh) return;
    p.mesh.traverse(obj => {
      if (obj.userData.isSelectionRing) {
        obj.material.opacity = (p.id === id) ? 0.8 : 0;
      }
    });
  });
}
